import { cursor } from './cursor';
import { gamePaused } from './game';
import { puzzleGrid } from './grid';
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
	[cursor, puzzleGrid, gamePaused],
	([$cursor, $puzzleGrid, $gamePaused]) => {
		return ($cursor.x === null && $cursor.y === null) || $puzzleGrid[$cursor.y][$cursor.x] !== 0 || $gamePaused;
	},
	false,
);
